import{_ as i,c as a,o as e,ag as t}from"./chunks/framework.GdcW6lnn.js";const c=JSON.parse('{"title":"Основы Docker: Образы (Images)","description":"","frontmatter":{},"headers":[],"relativePath":"basic_docker/docker_images.md","filePath":"basic_docker/docker_images.md"}'),l={name:"basic_docker/docker_images.md"};function n(h,s,r,k,o,p){return e(),a("div",null,s[0]||(s[0]=[t(`<h1 id="основы-docker-образы-images" tabindex="-1">Основы Docker: Образы (Images) <a class="header-anchor" href="#основы-docker-образы-images" aria-label="Permalink to “Основы Docker: Образы (Images)”">​</a></h1><p><strong>Docker Image</strong> — это шаблон, используемый для создания Docker-контейнеров. Образы являются неизменяемыми (read-only) файлами, которые состоят из серии слоев. Эти слои объединяются для создания файловой системы контейнера.</p><h2 id="основные-характеристики-docker-images" tabindex="-1">Основные характеристики Docker Images <a class="header-anchor" href="#основные-характеристики-docker-images" aria-label="Permalink to “Основные характеристики Docker Images”">​</a></h2><ul><li><strong>Слоистая файловая система (Layered Filesystem):</strong> Образы Docker состоят из нескольких слоев, каждый из которых представляет собой набор изменений в файловой системе. Эти слои создаются на основе инструкций в Dockerfile. Преимущество слоистой структуры заключается в том, что слои могут быть повторно использованы между различными образами, что экономит место на диске и ускоряет процесс сборки и передачи образов.</li><li><strong>Неизменяемость (Immutability):</strong> После создания образ не может быть изменен. Любые изменения приводят к созданию нового слоя поверх существующего образа.</li><li><strong>Портативность (Portability):</strong> Образы Docker можно легко передавать между различными Docker-хостами и хранить в Docker Registry.</li><li><strong>Рецепт для контейнеров:</strong> Образ содержит все необходимое для запуска одного или нескольких идентичных контейнеров.</li></ul><h2 id="управление-образами-docker" tabindex="-1">Управление образами Docker <a class="header-anchor" href="#управление-образами-docker" aria-label="Permalink to “Управление образами Docker”">​</a></h2><p>Вы можете управлять образами Docker с помощью команды <code>docker image</code> (или просто <code>docker</code>).</p><h3 id="просмотр-списка-образов" tabindex="-1">Просмотр списка образов <a class="header-anchor" href="#просмотр-списка-образов" aria-label="Permalink to “Просмотр списка образов”">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> images</span></span></code></pre></div><p>Эти команды выводят список всех образов, находящихся на вашем локальном Docker-хосте, включая их репозиторий, тег, ID образа, дату создания и размер.</p><ul><li><strong>REPOSITORY:</strong> Имя репозитория образа (например, <code>ubuntu</code>, <code>nginx</code>, <code>mysql</code>).</li><li><strong>TAG:</strong> Тег образа, который используется для версионирования (например, <code>latest</code>, <code>20.04</code>, <code>1.21</code>). По умолчанию используется тег <code>latest</code>, если не указан другой.</li><li><strong>IMAGE ID:</strong> Уникальный идентификатор образа.</li><li><strong>CREATED:</strong> Дата и время создания образа.</li><li><strong>SIZE:</strong> Размер образа.</li></ul><h3 id="поиск-образов-в-docker-hub" tabindex="-1">Поиск образов в Docker Hub <a class="header-anchor" href="#поиск-образов-в-docker-hub" aria-label="Permalink to “Поиск образов в Docker Hub”">​</a></h3><p>Docker Hub (<a href="https://hub.docker.com/" target="_blank" rel="noreferrer">https://hub.docker.com/</a>) — это публичный реестр образов Docker. Вы можете искать образы, используя команду <code>docker search</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ubuntu</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> is-official=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Поиск только официальных образов Ubuntu</span></span></code></pre></div><p>Результат поиска включает имя образа, описание, количество звезд (популярность), является ли образ официальным и автоматизированным.</p><h3 id="загрузка-образов-из-docker-hub" tabindex="-1">Загрузка образов из Docker Hub <a class="header-anchor" href="#загрузка-образов-из-docker-hub" aria-label="Permalink to “Загрузка образов из Docker Hub”">​</a></h3><p>Чтобы загрузить образ из Docker Hub на ваш локальный Docker-хост, используйте команду <code>docker pull</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ubuntu:latest</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Загрузка последней версии образа Ubuntu</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx:1.20</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # Загрузка образа Nginx с тегом 1.20</span></span></code></pre></div><p>Если тег не указан, Docker автоматически загрузит образ с тегом <code>latest</code>.</p><h3 id="создание-образов-dockerfile" tabindex="-1">Создание образов (Dockerfile) <a class="header-anchor" href="#создание-образов-dockerfile" aria-label="Permalink to “Создание образов (Dockerfile)”">​</a></h3><p>Образы Docker создаются на основе инструкций, содержащихся в файле <strong>Dockerfile</strong>. Мы подробно говорили о Dockerfile в предыдущей теме. Для сборки образа из Dockerfile используется команда <code>docker build</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-custom-image:1.0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div><ul><li><strong><code>-t my-custom-image:1.0</code>:</strong> Указывает имя и тег для создаваемого образа (<code>my-custom-image</code> — имя, <code>1.0</code> — тег). Если тег не указан, по умолчанию используется <code>latest</code>.</li><li><strong><code>.</code>:</strong> Указывает контекст сборки (обычно текущая директория), который содержит Dockerfile и другие необходимые файлы.</li></ul><h3 id="просмотр-истории-образа" tabindex="-1">Просмотр истории образа <a class="header-anchor" href="#просмотр-истории-образа" aria-label="Permalink to “Просмотр истории образа”">​</a></h3><p>Чтобы увидеть слои, составляющие образ, и команды, которые использовались для их создания, используйте команду <code>docker history</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> history</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ubuntu:latest</span></span></code></pre></div><p>Эта команда показывает слои в обратном хронологическом порядке (начиная с самого верхнего слоя).</p><h3 id="отметка-образов-тегами" tabindex="-1">Отметка образов тегами <a class="header-anchor" href="#отметка-образов-тегами" aria-label="Permalink to “Отметка образов тегами”">​</a></h3><p>Вы можете присваивать образам дополнительные теги для удобства управления версиями или для указания другого репозитория:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tag</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-custom-image:1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [my-registry.com/my-namespace/my-custom-image:latest](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://my-registry.com/my-namespace/my-custom-image:latest</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Эта команда создает новый тег <code>latest</code> для образа <code>my-custom-image:1.0</code> в репозитории <code>my-registry.com/my-namespace/</code>.</p><h3 id="выгрузка-образов-в-docker-registry" tabindex="-1">Выгрузка образов в Docker Registry <a class="header-anchor" href="#выгрузка-образов-в-docker-registry" aria-label="Permalink to “Выгрузка образов в Docker Registry”">​</a></h3><p>Чтобы поделиться своими образами или использовать их на другом Docker-хосте, вы можете выгрузить их в Docker Registry (например, Docker Hub или частный реестр) с помощью команды <code>docker push</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Если требуется аутентификация в реестре</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [my-registry.com/my-namespace/my-custom-image:latest](</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://my-registry.com/my-namespace/my-custom-image:latest</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="сохранение-и-загрузка-образов-локально" tabindex="-1">Сохранение и загрузка образов (локально) <a class="header-anchor" href="#сохранение-и-загрузка-образов-локально" aria-label="Permalink to “Сохранение и загрузка образов (локально)”">​</a></h3><p>Вы также можете сохранить образ в tar-архив и затем загрузить его на другом Docker-хосте без использования реестра:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> save</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-image.tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-custom-image:1.0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> load</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-image.tar</span></span></code></pre></div><h3 id="удаление-образов" tabindex="-1">Удаление образов <a class="header-anchor" href="#удаление-образов" aria-label="Permalink to “Удаление образов”">​</a></h3><p>Чтобы удалить один или несколько образов, используйте команду <code>docker rmi</code> (remove image):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rmi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-custom-image:1.0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Удаление образа по имени и тегу</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rmi</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">image_i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # Удаление образа по ID</span></span></code></pre></div><p><strong>Будьте осторожны при удалении образов, так как это необратимая операция. Убедитесь, что вы удаляете нужные образы.</strong></p><p>Чтобы удалить все неиспользуемые образы (образы, на которые не ссылаются ни один контейнер):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prune</span></span></code></pre></div><p>Чтобы удалить все неиспользуемые образы и связанные с ними данные (включая неиспользуемые контейнеры и сети):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> system</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prune</span></span></code></pre></div><p><strong>Также будьте осторожны при использовании <code>docker system prune</code>, так как это может удалить важные данные.</strong></p><h2 id="лучшие-практики-при-работе-с-docker-images" tabindex="-1">Лучшие практики при работе с Docker Images <a class="header-anchor" href="#лучшие-практики-при-работе-с-docker-images" aria-label="Permalink to “Лучшие практики при работе с Docker Images”">​</a></h2><ul><li><strong>Используйте минимальные базовые образы:</strong> Начинайте с небольших базовых образов (например, alpine-based), чтобы уменьшить размер и повысить безопасность ваших итоговых образов.</li><li><strong>Мультистейдж сборки (Multi-stage builds):</strong> Используйте несколько стадий в Dockerfile для сборки приложения и копирования только необходимых артефактов в финальный образ, что также уменьшает его размер.</li><li><strong>Кэширование слоев:</strong> Располагайте инструкции в Dockerfile таким образом, чтобы максимально эффективно использовать кэширование слоев Docker, что ускоряет процесс сборки.</li><li><strong>Регулярно обновляйте базовые образы:</strong> Следите за обновлениями безопасности базовых образов и пересобирайте свои образы при необходимости.</li><li><strong>Используйте теги для версионирования:</strong> Правильное использование тегов помогает отслеживать различные версии ваших образов.</li><li><strong>Оптимизируйте размер образов:</strong> Удаляйте ненужные файлы и зависимости из финальных образов.</li><li><strong>Безопасность образов:</strong> Сканируйте свои образы на наличие уязвимостей.</li></ul><p>Docker Images являются фундаментальной концепцией в Docker. Понимание того, как создавать, управлять и оптимизировать образы, является ключевым для эффективной работы с Docker.</p>`,48)]))}const g=i(l,[["render",n]]);export{c as __pageData,g as default};
